const { expect } = require('chai');
const Component = require('../../../../../src/lib/annotations/inject/Component');

describe('Component Annotation', () => {
  it('should store the provided arguments', () => {
    const args = ['AppService'];
    const annotation = new Component(args);

    expect(annotation.args).to.deep.equal(args);
  });

  it('should have default empty args if none provided', () => {
    const annotation = new Component();
    expect(annotation.args).to.deep.equal([]);
  });
});
